  ('cpa-moex-00070', 'cpa', 'cpa-moex-114-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得稅法規定，公益信託之信託利益，其課稅時點及課稅主體為何？', '["公益信託因具公益性質，不發生課稅問題", "於信託契約成立年度，對委託人課稅", "於所得發生年度，對受託人課稅", "於信託利益分配年度，對受益人課稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "994b415074d0", "answer_pdf_sha1": "4b61d7f7beb9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00071', 'cpa', 'cpa-moex-114-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '下列那些交易免依所得稅法第4條之4規定適用房地合一稅制課徵所得稅？①105年1月', '["110年1月出售依農業發展條例 申請興建之農舍", "105年1月5日取得並於110年12月31日被徵收之土地及其土地改良 物", "106年間取得之全新電梯大樓，於110年7月31日虧損售出", "僅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "994b415074d0", "answer_pdf_sha1": "4b61d7f7beb9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00072', 'cpa', 'cpa-moex-114-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得稅法規定，下列所得何者應計入個人取得年度之綜合所得總額？', '["於跳蚤市場拍賣個人過季二手衣物之交易所得", "將長輩贈送金塊於網路平臺出售之交易所得", "於我國證券交易市場出售國內投信業者發行ETF（ExchangeTradedFunds）之交易所得", "擔任我國私立大學學生入學考試監考人員取得之報酬"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "994b415074d0", "answer_pdf_sha1": "4b61d7f7beb9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00073', 'cpa', 'cpa-moex-114-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '甲單身未婚，113年綜合所得總額1,000萬元，熱愛棒球，113年初即經由教育部設置的「個 人捐贈運動員專戶」，指定捐贈特定運動員500萬元；同年5月5日捐贈300萬元，未指定特 定運動員，若甲113年度無其他贈與行為，則甲113年度綜合所得稅捐贈列舉扣除額及應納 贈與稅額分別為何？', '["800萬元、0元", "700萬元、0元", "500萬元、5.6萬元", "300萬元、25.6萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "994b415074d0", "answer_pdf_sha1": "4b61d7f7beb9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00074', 'cpa', 'cpa-moex-114-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '甲公司經營塑膠原料批發業，113年度營利事業所得稅結算申報營業收入2,000萬元、非營業 收入100萬元及非營業損失50萬元，甲公司如依擴大書面審核實施要點規定申報，當年度擴 大書審純益率為6%，則甲公司應申報課稅所得額為多少元？', '["220萬元", "170萬元", "126萬元", "123萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "994b415074d0", "answer_pdf_sha1": "4b61d7f7beb9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00075', 'cpa', 'cpa-moex-114-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '總機構在中華民國境外之影片事業在境內無分支機構而有營業代理人，113 年度提供影片供 境內營利事業放映使用，經約定影片不得重製及提供他人使用，且應於一定期限放映。設該 影片事業113年度境內收入為1,000萬元，依所得稅法及相關規定，其課稅所得額為何？', '["100萬元", "200萬元", "450萬元", "500萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "994b415074d0", "answer_pdf_sha1": "4b61d7f7beb9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00076', 'cpa', 'cpa-moex-114-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '下列交易何者應依所得稅法第4條之4規定，課徵房地合一所得稅？', '["甲於民國90年買入房地一處，但因病於民國113年過世，該房地由其兒子繼承並立即出售", "乙於民國113年出售其於民國90年取得之未上市A公司股權，乙直接持有A公司股權過 半數，且A公司股權之價值50%以上係由中華民國境內之房屋、土地所構成", "丙於民國113年出售房地，該房地係丙之配偶丁於民國100年購入，嗣後於民國110年贈 與給丙", "戊於民國110年購入預售屋一處，於民國113年交屋完成移轉登記之後迄今未出售"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "994b415074d0", "answer_pdf_sha1": "4b61d7f7beb9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00077', 'cpa', 'cpa-moex-114-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '個人交易符合所得稅法第4條之5房地合一所得稅制免稅範圍之下列房屋、土地，且計算結 果為交易損失，何者仍應辦理申報？', '["符合農業發展條例第37條及第38條之1規定得申請不課徵土地增值稅之土地", "被徵收或被徵收前先行協議價購之土地及其土地改良物", "尚未被徵收前移轉依都市計畫法指定之公共設施保留地", "適用自住房地租稅優惠之房屋、土地"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "994b415074d0", "answer_pdf_sha1": "4b61d7f7beb9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00078', 'cpa', 'cpa-moex-114-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '下列何者應依所得基本稅額條例之規定計算繳納所得基本稅額？', '["獨資或合夥組織之營利事業", "符合行政院規定標準之教育、文化、公益、慈善機關或團體", "在中華民國境內無固定營業場所及營業代理人之營利事業", "所得稅結算申報適用投資抵減獎勵且其計算之基本所得額在新臺幣60萬元以上之營利事業"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "994b415074d0", "answer_pdf_sha1": "4b61d7f7beb9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00079', 'cpa', 'cpa-moex-114-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '個人及其關係人直接或間接持有在中華民國境外低稅負國家或地區之關係企業股份或資本額 合計達50%以上或對該關係企業具有重大影響力，且該關係企業無所得稅法第43條之3第1 項各款規定者，則於個人或其與配偶及二親等以內親屬合計持有該關係企業股份或資本額多 少比率以上，該個人應將該關係企業當年度之盈餘，按其持有該關係企業股份或資本額之比 率計算營利所得，計入當年度個人之基本所得額？', '["2%", "5%", "10%", "20%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:58+00:00", "source_pdf_sha1": "994b415074d0", "answer_pdf_sha1": "4b61d7f7beb9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
